arguments.command:
# Found the right auth pattern. Now get all tables
cd ~/.openclaw/workspace/tools && .venv/bin/python3 << 'PYEOF'
import os, urllib.request, json

base = os.environ['SUPABASE_URL'] + '/rest/v1/'
anon = os.environ['SUPABASE_ANON_KEY']
headers = {'apikey': anon, 'Authorization': f'Bearer {anon}', 'Prefer': 'count=exact'}

# Get table list from OpenAPI
try:
    req = urllib.request.Request(base, headers={'apikey': anon, 'Authorization': f'Bearer {anon}'})
    resp = urllib.request.urlopen(req)
    data = json.loads(resp.read())
    if isinstance(data, dict) and 'definitions' in data:
        table_names = list(data['definitions'].keys())
    else:
        table_names = []
except:
    table_names = []

if not table_names:
    # Try known tables
    table_names = ['sai_contacts', 'sai_memory', 'sai_conversations', 'sai_beings', 'sai_colosseum_battles', 'sai_colosseum_beings', 'sai_email_colosseum_battles', 'sai_email_colosseum_beings', 'sai_sister_updates']

for t in sorted(table_names):
    try:
        req = urllib.request.Request(
            f'{base}{t}?select=id&limit=0',
            headers={**headers}
        )
        resp = urllib.request.urlopen(req)
        cr = resp.headers.get('Content-Range', 'no-range')
        print(f'  {t}: {cr}')
    except urllib.error.HTTPError as e:
        body = e.read().decode()[:80]
        if e.code == 404:
            pass  # table doesn't exist
        else:
            print(f'  {t}: {e.code} — {body}')
    except Exception as e:
        print(f'  {t}: {str(e)[:60]}')
PYEOF

