# Convert markdown to styled HTML then to PDF via weasyprint
cd ~/.openclaw/workspace && pandoc reports/colosseum-launch-sop.md \
  -o /tmp/colosseum-launch-sop.html \
  --standalone \
  --metadata title="SOP — Colosseum Launch Campaign" \
  --css=/dev/null 2>&1

# Now inject styling and convert with weasyprint
cat > /tmp/sop-to-pdf.py << 'PYEOF'
import re

# Read the HTML pandoc generated
with open('/tmp/colosseum-launch-sop.html') as f:
    html = f.read()

# Inject custom CSS
css = """
<style>
  @page { margin: 0.75in; size: letter; }
  body { 
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; 
    font-size: 10.5pt; 
    line-height: 1.5; 
    color: #1a1a1a;
    max-width: 100%;
  }
  h1 { 
    font-size: 22pt; 
    color: #0f0f23; 
    border-bottom: 3px solid #e63946; 
    padding-bottom: 8px; 
    margin-bottom: 4px;
  }
  h2 { 
    font-size: 15pt; 
    color: #1d3557; 
    margin-top: 24px; 
    border-bottom: 1px solid #ddd;
    padding-bottom: 4px;
  }
  h3 { 
    font-size: 12pt; 
    color: #457b9d; 
    margin-top: 16px; 
  }
  table { 
    border-collapse: collapse; 
    width: 100%; 
    margin: 12px 0; 
    font-size: 9.5pt;
  }
  th { 
    background: #1d3557; 
    color: white; 
    padding: 8px 10px; 
    text-align: left; 
    font-weight: 600;
  }
  td { 
    padding: 6px 10px; 
    border-bottom: 1px solid #e0e0e0; 
  }
  tr:nth-child(even) td { background: #f8f9fa; }
  code, pre { 
    background: #f4f4f4; 
    padding: 2px 5px; 
    border-radius: 3px; 
    font-size: 9pt;
  }
  pre { 
    padding: 12px; 
    overflow-x: auto; 
    border: 1px solid #ddd;
    border-radius: 4px;
  }
  blockquote { 
    border-left: 4px solid #e63946; 
    padding-left: 12px; 
    margin-left: 0; 
    color: #555; 
    font-style: italic;
  }
  em { color: #555; }
  strong { color: #0f0f23; }
  hr { border: none; border-top: 2px solid #e63946; margin: 20px 0; }
  ul, ol { padding-left: 20px; }
  li { margin-bottom: 4px; }
  .subtitle { font-size: 11pt; color: #666; margin-top: -4px; margin-bottom: 16px; }
</style>
"""

html = html.replace('</head>', css + '</head>')

# Write styled HTML
with open('/tmp/colosseum-launch-sop-styled.html', 'w') as f:
    f.write(html)

# Convert to PDF
from weasyprint import HTML
HTML(filename='/tmp/colosseum-launch-sop-styled.html').write_pdf(
    '~/.openclaw/workspace/reports/colosseum-launch-sop.pdf'
)
print("PDF generated successfully")
PYEOF

